mapper.update:
UPDATE tuyen_duong SET diem_di = #{diemDi}, diem_den = #{diemDen},
    khoang_cach_km = #{khoangCachKm}, thoi_gian_uoc_tinh_phut = #{thoiGianUocTinhPhut}, hoat_dong = #{hoatDong}
WHERE ma = #{ma}

mapper.select:
SELECT * FROM tuyen_duong WHERE LOWER(TRIM(diem_di)) = LOWER(TRIM(#{diemDi})) AND LOWER(TRIM(diem_den)) = LOWER(TRIM(#{diemDen}))
AND ma != #{maLoaiTru}
LIMIT 1
